---
import type { HTMLAttributes } from "astro/types";
import { cn } from "@/lib/utils";
import NavigationMenuViewport from "./NavigationMenuViewport.astro";

interface Props extends HTMLAttributes<"div"> {
  class?: string;
  align?: "start" | "center" | "end";
  alignOffset?: number;
  side?: "top" | "bottom";
  sideOffset?: number;
}

const {
  class: className = "",
  side = "bottom",
  sideOffset = 8,
  align = "start",
  alignOffset = 0,
  ...rest
} = Astro.props as Props;
---

<div data-slot="navigation-menu-portal">
  <div
    {...rest}
    data-slot="navigation-menu-positioner"
    data-side={side}
    data-side-offset={sideOffset}
    data-align={align}
    data-align-offset={alignOffset}
    class={cn(
      "transition-[top,left,right,bottom] duration-300 ease-[cubic-bezier(0.22,1,0.36,1)] data-[side=bottom]:before:top-[-10px] data-[side=bottom]:before:right-0 data-[side=bottom]:before:left-0 isolate z-50 h-(--positioner-height) w-(--positioner-width) max-w-(--available-width) duration-[0.35s] data-instant:transition-none",
      className,
    )}
  >
    <div
      data-slot="navigation-menu-popup"
      class="bg-popover text-popover-foreground ring-foreground/10 rounded-none shadow ring-1 transition-all ease-[cubic-bezier(0.22,1,0.36,1)] outline-none data-ending-style:scale-90 data-ending-style:opacity-0 data-ending-style:duration-150 data-starting-style:scale-90 data-starting-style:opacity-0 data-[ending-style]:easing-[ease] xs:w-(--popup-width) relative h-(--popup-height) w-(--popup-width) origin-(--transform-origin) transition-[opacity,transform,width,height,scale,translate] duration-[0.35s]"
    >
      <NavigationMenuViewport />
    </div>
  </div>
</div>
